evals.prompt:
Refactor this legacy Angular service to use @ngrx/signals. Keep the public API behavior the same so existing components don't break (they use products$ today via the async pipe — show me how to migrate the template too). Here is the service:

```typescript
@Injectable({ providedIn: 'root' })
export class ProductsService {
  private readonly _products$ = new BehaviorSubject<Product[]>([]);
  private readonly _isLoading$ = new BehaviorSubject<boolean>(false);
  readonly products$ = this._products$.asObservable();
  readonly isLoading$ = this._isLoading$.asObservable();
  readonly inStockProducts$ = this.products$.pipe(map(p => p.filter(x => x.stock > 0)));

  constructor(private http: HttpClient) {}

  loadAll() {
    this._isLoading$.next(true);
    this.http.get<Product[]>('/api/products').subscribe({
      next: products => { this._products$.next(products); this._isLoading$.next(false); },
      error: () => this._isLoading$.next(false),
    });
  }

  add(product: Product) {
    this._products$.next([...this._products$.value, product]);
  }
}
```

Produce: (1) a new ProductsApiService that owns the HTTP call, (2) a ProductsStore using @ngrx/signals replacing the BehaviorSubject service, (3) a sample component snippet showing how a consumer migrates from `products$ | async` to the signal-based API.
